<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1, maximum-scale=1, user-scalable=no" />
  <title>Photoganic — A Gentler Way to Capture Joy</title>
  <style>
    /* ─── Brand tokens ─────────────────────────────────────────── */
    :root {
      --bg: #FFFCF4;
      --surface: #FFFCF4;
      --fg: #0C642C;
      --muted: #599D9C;
      --border: #A0A88C;
      --accent: #0C642C;
      --accent-on: #FFFCF4;
      --spearmint: #599D9C;
      --sage: #A0A88C;

      --font-display: "Times New Roman MT Condensed", Georgia, "Times New Roman", serif;
      --font-body: Montserrat, system-ui, -apple-system, sans-serif;
      --font-size-body: 15px;
      --radius-card: 16px;
      --radius-btn: 10px;
      --ease-calm: 300ms cubic-bezier(0.4, 0, 0.2, 1);
    }

    * { box-sizing: border-box; margin: 0; padding: 0; }

    html {
      scroll-behavior: smooth;
    }

    html, body {
      width: 100%;
      min-height: 100vh;
      background: #ebe6db;
      font-family: var(--font-body);
      font-size: var(--font-size-body);
      color: var(--fg);
      -webkit-font-smoothing: antialiased;
      -moz-osx-font-smoothing: grayscale;
      display: flex;
      justify-content: center;
    }

    /* ─── Device frame ──────────────────────────────────────────── */
    .phone-frame {
      width: 390px;
      max-width: 100%;
      min-height: 100dvh;
      background: var(--bg);
      display: flex;
      flex-direction: column;
      position: relative;
      box-shadow:
        0 0 0 1px rgba(0,0,0,0.08),
        0 20px 60px rgba(0,0,0,0.15),
        0 8px 20px rgba(0,0,0,0.08);
    }

    @media (max-width: 430px) {
      .phone-frame {
        box-shadow: none;
        min-height: 100dvh;
      }
    }

    /* ─── Status bar ────────────────────────────────────────────── */
    .status-bar {
      display: flex;
      justify-content: space-between;
      align-items: center;
      padding: 12px 20px 0;
      font-size: 12px;
      font-weight: 600;
      font-family: var(--font-body);
      color: var(--fg);
      letter-spacing: 0.3px;
      flex-shrink: 0;
      background: var(--bg);
      position: relative;
      z-index: 10;
    }

    /* ─── Sticky nav ────────────────────────────────────────────── */
    .site-header {
      position: sticky;
      top: 0;
      z-index: 20;
      background: var(--bg);
      border-bottom: 1px solid var(--sage);
      flex-shrink: 0;
    }

    .nav-bar {
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: 14px 20px;
    }

    .wordmark {
      font-family: var(--font-display);
      font-size: 22px;
      font-weight: 700;
      letter-spacing: -0.02em;
      color: var(--fg);
      text-decoration: none;
      line-height: 1;
      display: flex;
      align-items: center;
      gap: 4px;
    }

    .wordmark::before {
      content: "";
      display: inline-block;
      width: 24px;
      height: 24px;
      background: var(--fg);
      border-radius: 4px;
      margin-right: 6px;
      flex-shrink: 0;
    }

    .wordmark em {
      font-style: italic;
      font-weight: 700;
    }

    .hamburger {
      width: 44px;
      height: 44px;
      border: 0;
      background: transparent;
      cursor: pointer;
      display: flex;

